import React, { useState, useRef, useEffect } from 'react';
import { MessageSquare, X, Send, Bot, User } from 'lucide-react';
import { sendMessageToGemini } from '../services/geminiService';
import { ChatMessage, ChatSender } from '../types';

export const ChatWidget: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '1',
      text: "Hello! I'm your Carolinas Mobile Home assistant. I can help with questions about title transfers, park approvals, and our guaranteed pricing model. How can I assist you today?",
      sender: ChatSender.BOT,
      timestamp: new Date()
    }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      text: input,
      sender: ChatSender.USER,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    const history = messages.map(m => `${m.sender === ChatSender.USER ? 'User' : 'Assistant'}: ${m.text}`);

    const responseText = await sendMessageToGemini(history, userMsg.text);

    const botMsg: ChatMessage = {
      id: (Date.now() + 1).toString(),
      text: responseText,
      sender: ChatSender.BOT,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, botMsg]);
    setIsLoading(false);
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSend();
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {!isOpen && (
        <button
          onClick={() => setIsOpen(true)}
          className="bg-blue-900 hover:bg-blue-800 text-white rounded-full p-5 shadow-2xl flex items-center justify-center transition-all hover:scale-110 group relative"
        >
          <div className="absolute -top-2 -right-2 w-5 h-5 bg-amber-500 rounded-full animate-ping"></div>
          <MessageSquare className="w-8 h-8" />
        </button>
      )}

      {isOpen && (
        <div className="bg-white rounded-3xl shadow-2xl w-80 sm:w-96 flex flex-col h-[550px] border border-gray-100 overflow-hidden animate-in slide-in-from-bottom-5 duration-300">
          <div className="bg-blue-900 p-5 flex justify-between items-center text-white">
            <div className="flex items-center">
              <div className="w-3 h-3 bg-green-400 rounded-full mr-3 animate-pulse"></div>
              <div>
                <span className="font-bold block">Mobile Home Specialist</span>
                <span className="text-[10px] uppercase tracking-widest text-blue-300">Online Assistant</span>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="bg-white/10 hover:bg-white/20 rounded-full p-2 transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-5 bg-gray-50 space-y-4">
            {messages.map((msg) => (
              <div
                key={msg.id}
                className={`flex ${msg.sender === ChatSender.USER ? 'justify-end' : 'justify-start'}`}
              >
                <div
                  className={`max-w-[85%] rounded-2xl p-4 text-sm leading-relaxed ${
                    msg.sender === ChatSender.USER
                      ? 'bg-blue-600 text-white rounded-tr-none shadow-md'
                      : 'bg-white border border-gray-200 text-gray-800 rounded-tl-none shadow-sm'
                  }`}
                >
                  {msg.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-gray-200 rounded-2xl p-4 rounded-tl-none">
                  <div className="flex space-x-2">
                    <div className="w-2 h-2 bg-blue-300 rounded-full animate-bounce"></div>
                    <div className="w-2 h-2 bg-blue-300 rounded-full animate-bounce [animation-delay:-.3s]"></div>
                    <div className="w-2 h-2 bg-blue-300 rounded-full animate-bounce [animation-delay:-.5s]"></div>
                  </div>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          <div className="p-4 border-t border-gray-100 bg-white">
            <div className="flex items-center space-x-3">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyPress}
                placeholder="Ask about title transfers or pricing..."
                className="flex-1 border border-gray-200 rounded-2xl px-5 py-3 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 text-sm bg-gray-50 transition-all"
              />
              <button
                onClick={handleSend}
                disabled={isLoading}
                className="bg-amber-600 text-white p-3 rounded-2xl hover:bg-amber-700 disabled:opacity-50 shadow-md transition-colors"
              >
                <Send className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

// Initialize the Gemini API client directly with process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
You are the virtual assistant for "SC & NC Mobile Home Buyer", a specialized mobile home solutions company based in the Carolinas.
Your tone is professional, empathetic, and knowledgeable about manufactured housing.

Strict Rules on Terminology:
- NEVER use the term "real estate" or "real estate agent". 
- Use "Mobile Home Specialist" or "Manufactured Home Solutions".
- Refer to properties as "mobile homes", "manufactured homes", or "properties".
- Refer to the closing process as "title transfer" or "the transfer process".

Key Business Logic:
- We operate in South Carolina (SC) and North Carolina (NC).
- We specialize in mobile homes on land AND in parks (leased land).
- We guarantee a purchase price for mobile homes.
- UNIQUE MODEL: If we find a buyer who will pay more for the home than our guaranteed price, the seller keeps 100% of that extra profit. We are compensated by the end-buyer, not the seller.
- We buy "As-Is" and can complete the title transfer in as little as 7 days.
- We handle all manufactured-home-specific paperwork (DMV titles, park management approvals).

If a user asks for a specific price, explain that we need to analyze their home's details first. Encourage them to fill out the form or call.
`;

export const sendMessageToGemini = async (history: string[], message: string): Promise<string> => {
  try {
    // Convert history strings to the Content format expected by the GenerateContent API
    const historyParts = history.map(line => {
      const [role, ...textParts] = line.split(': ');
      return {
        role: role.toLowerCase() === 'user' ? 'user' : 'model',
        parts: [{ text: textParts.join(': ') }]
      };
    });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...historyParts,
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        // Apply system instructions via config as recommended in current guidelines
        systemInstruction: SYSTEM_INSTRUCTION,
      }
    });

    // Access text directly from the response object
    return response.text || "I'm sorry, I didn't quite get that. Could you tell me more about your mobile home?";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm having trouble connecting right now. Please try again or call us!";
  }
};

