                    <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide mb-1">Location Type</label>
                    <select name="locationType" required value={formData.locationType} onChange={handleChange} className="w-full px-5 py-4 rounded-xl border-gray-200 shadow-sm focus:border-blue-500 focus:ring-blue-500 bg-gray-50 border transition-all">
                      <option value="">Where is it located?</option>
                      <option value="park">In a Mobile Home Park</option>
                      <option value="private-land">On Private Owned Land</option>
                      <option value="family">Family/Heir Property</option>
                    </select>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide mb-1">Property Address</label>
                  <input type="text" name="address" required value={formData.address} onChange={handleChange} className="w-full px-5 py-4 rounded-xl border-gray-200 shadow-sm focus:border-blue-500 focus:ring-blue-500 bg-gray-50 border transition-all" placeholder="City & State (SC or NC)" />
                </div>

                <div>
                  <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide mb-1">Notes (Age, Condition, Park Name)</label>
                  <textarea name="message" rows={3} value={formData.message} onChange={handleChange} className="w-full px-5 py-4 rounded-xl border-gray-200 shadow-sm focus:border-blue-500 focus:ring-blue-500 bg-gray-50 border transition-all" placeholder={isVideoRequest ? "Tell us when would be a good time for a video walkthrough..." : "Any specific details help us value it faster..."} />
                </div>

                <button type="submit" disabled={isSubmitting} className="w-full py-5 px-6 rounded-xl shadow-lg text-xl font-bold text-white bg-amber-600 hover:bg-amber-700 disabled:opacity-70 transition-all transform hover:scale-[1.02]">
                  {isSubmitting ? 'Processing Request...' : (isVideoRequest ? 'Request Video Walkthrough' : 'Get My Guaranteed Price')}
                </button>
              </form>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

