import React, { useEffect, useState } from 'react';
import { Header } from './components/Header';
import { Hero } from './components/Hero';
import { Features } from './components/Features';
import { HowItWorks } from './components/HowItWorks';
import { DealGallery } from './components/DealGallery';
import { Testimonials } from './components/Testimonials';
import { ContactForm } from './components/ContactForm';
import { BlogSection } from './components/BlogSection';
import { Footer } from './components/Footer';
import { ChatWidget } from './components/ChatWidget';
import { SellerApplication } from './components/SellerApplication';

const App: React.FC = () => {
  const [isAppOpen, setIsAppOpen] = useState(false);

  useEffect(() => {
    // Smooth scroll for anchor links
    document.querySelectorAll('a[href^="#"]').forEach(anchor => {
      anchor.addEventListener('click', function (e) {
        const href = (e.currentTarget as HTMLAnchorElement).getAttribute('href');

        // Intercept application hash
        if (href === '#apply' || href === '#video-request') {
          e.preventDefault();
          setIsAppOpen(true);
          return;
        }

        if (href && href !== '#') {
          e.preventDefault();
          const element = document.querySelector(href);
          element?.scrollIntoView({
            behavior: 'smooth'
          });
        }
      });
    });

    // Check hash on load
    if (window.location.hash === '#apply' || window.location.hash === '#video-request') {
      setIsAppOpen(true);
    }
  }, []);

  return (
    <div className="min-h-screen bg-white">
      <Header onApply={() => setIsAppOpen(true)} />
      <main>
        <Hero onApply={() => setIsAppOpen(true)} />
        <Features />
        <HowItWorks />
        <DealGallery />
        <Testimonials />
        <BlogSection />
        <ContactForm />
      </main>
      <Footer />
      <ChatWidget />

      <SellerApplication 
        isOpen={isAppOpen} 
        onClose={() => {
          setIsAppOpen(false);
          window.location.hash = '';
        }} 
      />
    </div>
  );
};

export default App;

