interface SellerApplicationProps {
  isOpen: boolean;
  onClose: () => void;
}

export const SellerApplication: React.FC<SellerApplicationProps> = ({ isOpen, onClose }) => {
  const [step, setStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState('');

  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    email: '',
    address: '',
    year: '',
    condition: 'good',
    message: ''
  });

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      setStep(1);
      setError('');
    } else {
      document.body.style.overflow = 'unset';
    }
  }, [isOpen]);

  const validateStep = () => {
    setError('');
    if (step === 1) {
      if (!formData.name.trim() || !formData.phone.trim() || !formData.email.trim()) {
        setError('Please fill in all contact fields.');
        return false;
      }
    }
    if (step === 2 && !formData.address.trim()) {
      setError('Property address is required.');
      return false;
    }
    return true;
  };

  const handleNext = () => {
    if (validateStep()) setStep(s => s + 1);
  };

  const handleBack = () => setStep(s => s - 1);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateStep()) return;

    setIsSubmitting(true);
    try {
      await apiService.submitLead({
        type: 'seller',
        ...formData
      });
      setIsSuccess(true);
    } catch (err) {
      setError('Connection to CRM failed. Please check your internet and try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

