export const apiService = {
  // Auth Simulation
  getCurrentUser: (): User => getDB().users[0], // Mocking login session

  // Listings
  getListings: (tenantId?: string) => {
    const db = getDB();
    return tenantId ? db.listings.filter(l => l.tenant_id === tenantId) : db.listings;
  },

  createListing: (listing: Omit<Listing, 'id' | 'created_at' | 'status'>) => {
    const db = getDB();
    const newListing: Listing = {
      ...listing,
      id: 'l' + Date.now(),
      status: 'pending',
      created_at: new Date().toISOString()
    };
    db.listings.push(newListing);
    saveDB(db);
    return newListing;
  },

  updateListingStatus: (id: string, status: Listing['status']) => {
    const db = getDB();
    const listing = db.listings.find(l => l.id === id);
    if (listing) listing.status = status;
    saveDB(db);
  },

  // Offers
  createOffer: (offer: Omit<Offer, 'id' | 'created_at' | 'status'>) => {
    const db = getDB();
    const newOffer: Offer = {
      ...offer,
      id: 'o' + Date.now(),
      status: 'pending',
      created_at: new Date().toISOString()
    };
    db.offers.push(newOffer);
    saveDB(db);
    return newOffer;
  },

  acceptOffer: (offerId: string) => {
    const db = getDB();
    const offer = db.offers.find(o => o.id === offerId);
    if (!offer) return;

    offer.status = 'accepted';
    const listing = db.listings.find(l => l.id === offer.listing_id);
    if (listing) listing.status = 'sold';

    // Create Transaction
    const transaction: Transaction = {
      id: 'tx' + Date.now(),
      offer_id: offerId,
      escrow_transaction_id: 'ESC-' + Math.random().toString(36).substring(7).toUpperCase(),
      status: 'created',
      buyer_id: offer.buyer_id,
      seller_id: listing?.seller_id || '',
      amount: offer.amount,
      escrow_fee: offer.amount * 0.0089,
      platform_fee: offer.amount * 0.02
    };
    db.transactions.push(transaction);
    saveDB(db);
    return transaction;
  },

  getTransactions: (userId: string, role: UserRole) => {
    const db = getDB();
    if (role === 'seller') return db.transactions.filter(t => t.seller_id === userId);
    if (role === 'buyer') return db.transactions.filter(t => t.buyer_id === userId);
    return db.transactions;
  }
};

